import React, { useState, useRef } from "react";

import "./App.css";
import { array_of_mutants, Original } from "./mutants";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/
var spending;
var claimReduction = false;
var valueInit = true;

function Grocery() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed, setKilled] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);
  //var [spending, setSpending] = useState("");
  var [totalSpending, setTotalSpending] = useState(0);

  var [reducedPrice, setReducedPrice] = useState(0);
  var [reduction, setReduction] = useState(0);
  var spendingInput = useRef();

  var resultOrig;

  function nextTest() {
    // xInput.current.value = "";

    // setSpending(0);
    setTotalSpending(0);
    //  setEredmeny(0);
    init();
  }

  function tryAgain() {
    // window.location.href = '/'
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
      mutant[i] = "";
    }
    nextTest();
    setNumber(0);
    testCaseNumber = 0;
    setPrintWrongTests("");
    setResult("");
    setMissing("");
  }

  function init() {
    /*
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
      mutant[i] = "";
    }
    */
    // setNumber(0);
    setEredmeny(0);
    setWrongSolution(false);
    setReducedPrice(0);
    setReduction(0);
    spending = 0;
    wrongTests[0] = "";
    claimReduction = false;
    if (spendingInput.current) spendingInput.current.value = "";
  }

  function callFunctions(operation) {
    var totalPrice = 0;
    var mutantResult;
    var killedMutants1 = "";
    console.log("operation: ", operation);
    resultOrig = Original(
      +spending,
      totalSpending,
      claimReduction,
      operation,
      0
    );
    setTotalSpending(resultOrig.totalSpending);
    setReduction(resultOrig.reduction);
    ////  setEredmeny(result);
    var superfluousTest = true;

    ////  setWrongSolution(wrongSolution);
    //// setKilledMutants(killedMutants1);
    testCaseNumber++;
    setNumber(testCaseNumber);
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        mutantResult = array_of_mutants[i](
          +spending,
          totalSpending,
          claimReduction,
          operation,
          i + 1
        );
        mutant[i] = mutantResult.mutant;

        if (
          +resultOrig.totalSpending !== +mutantResult.totalSpending ||
          +resultOrig.reduction !== +mutantResult.reduction //||
          // +resultOrig.spending !== +mutantResult.spending
        ) {
          var j = i + 1;
          killedMutants1 = killedMutants1 + j + " ";
          killed[i] = true;
          mutant[i] = "";
          superfluousTest = false;
          console.log("killed mutant: ", i + 1);
        }
      }
    }
  }

  function handleChange(eventChange) {
    spending = eventChange.target.value;
    claimReduction = false;
    reducedPrice = +spending;
    setReducedPrice(reducedPrice);
    //  console.log("spending:", spending);
  }

  /*
  function handleKeyDown(event) {
    var x = event.key;
    if (x === "Enter" || x === "Tab") {
      claimReduction = false;
      reducedPrice = +spending;
      setReducedPrice(reducedPrice);
    }
  }
  */

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        {console.log("---------------------------")}
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          <a href="https://harmony.test-design.org/"> Harmony Exercises</a> to
          make action-state test design and execute tests automatedly.
        </p>

        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Online grocery </b>
          </div>
          In an online grocery, you have the following price reduction.
          <br />
          <b>R1</b> If you buy for at least EUR 1000 within a calendar year then
          a 5% price reduction can be claimed for the subsequent purchases in
          that calendar year.
          <br />
          <b>R2</b> When you claim a price reduction, the amount you currently
          spend is not involved in the calendar year (total) spending. <br />
          <b>R3</b> If you don’t ask for price reduction then the double amount
          of the current purchase is added to your total spending. <br />
          <b>R4</b> If your total spending with corrections reaches EUR 2000,
          then an 8% reduction can be claimed and if you ask for this price
          reduction, the current amount is added to your calendar year spending.
          <br />
          <b>R5</b> If your total spending with corrections reaches EUR 3000,
          then in the subsequent calendar year your initial spending is 25% of
          your previous year total spending (instead of zero). <br />
          <b>R6</b> The total spending with corrections is displayed when you
          enter the grocery and is not changing during your purchase. <br />
          <b>R7</b> The price to be paid for your purchase is displayed.
          &nbsp;&nbsp; <br />A purchase happens after clicking on 'I buy it'.
          The input price accuracy is 1.
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          Total spending:{" "}
          <span data-harmony-id="Total price">{totalSpending} </span>
          &nbsp;&nbsp;&nbsp; Price reduction %:{" "}
          <span data-harmony-id="Reduction">{reduction} </span>{" "}
          &nbsp;&nbsp;&nbsp; Price (EUR):{" "}
          <input
            size="2"
            data-harmony-id="Price"
            ref={spendingInput}
            onChange={handleChange}
            //   onKeyDown={handleKeyDown}
          />
          &nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Ask reduction"
            onClick={() => {
              //   if (totalSpending >= 1000)
              claimReduction = true;
              reducedPrice = +spending * (1 - reduction / 100);
              setReducedPrice(reducedPrice);
              //  callFunctions("ask reduction");
            }}
          >
            {" "}
            I demand reduction{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp; Price to pay:{" "}
          <span data-harmony-id="Price to pay">{reducedPrice} </span>
          &nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Buy"
            onClick={() => {
              callFunctions("next purchase");
              if (spendingInput.current) spendingInput.current.value = "";
              setReducedPrice(0);
              spending = resultOrig.spending;
            }}
          >
            {" "}
            I buy it{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Next year"
            onClick={() => {
              callFunctions("next year");
              if (spendingInput.current) spendingInput.current.value = "";
              setReducedPrice(0);
              spending = resultOrig.spending;
            }}
          >
            {" "}
            Next year{" "}
          </button>{" "}
          <br /> <br />
          <button class="button" data-harmony-id="Next test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          {/*
          <button
            class="download"
            data-harmony-id="Download"
            onClick={downloadTasks}
          >
            {" "}
            Download templates{" "}
          </button>{" "}
          <a
            id="downloader"
            href="../templates/pizza_templates.zip"
            download
            hidden
          ></a>
          */}
          <br />
        </p>
      </header>
    </div>
  );
}

export default Grocery;
